function ContactLink({ href, label, value, iconPath }) {
  const [hover, setHover] = useState(false);
  return (
    <a href={href} target={href.startsWith("http") ? "_blank" : undefined} style={{
      display:"flex", alignItems:"center", gap:"1.2rem",
      textDecoration:"none", padding:"1.2rem 1.5rem",
      borderRadius:"1rem",
      background: hover ? "rgba(208,59,42,0.12)" : "rgba(253,252,249,0.05)",
      border:`1px solid ${hover ? "rgba(208,59,42,0.4)" : "rgba(253,252,249,0.1)"}`,
      transform: hover ? "translateX(6px)" : "translateX(0)",
      transition:"all 0.2s"
    }}
    onMouseEnter={() => setHover(true)}
    onMouseLeave={() => setHover(false)}
    >
      <div style={{
        width:40, height:40, borderRadius:"0.7rem",
        background:"rgba(208,59,42,0.15)",
        display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0
      }}>
        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={C.red} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
          {iconPath.split("M").filter(Boolean).map((d,i) => <path key={i} d={"M"+d} />)}
        </svg>
      </div>
      <div>
        <div style={{ fontSize:"0.7rem", textTransform:"uppercase", letterSpacing:"0.1em", color:"rgba(253,252,249,0.4)", marginBottom:"0.2rem" }}>{label}</div>
        <div style={{ fontSize:"0.9rem", fontWeight:500, color:C.white }}>{value}</div>
      </div>
    </a>
  );
}

